import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    cmd = inp.get("command", "").strip()

    # Block: pnpm test (without --run or :ci variant)
    if cmd == "pnpm test" or cmd.startswith("pnpm test "):
        # Allow pnpm test:ci, pnpm test -- --run, etc.
        if " --run" not in cmd and ":ci" not in cmd and "-- " not in cmd:
            msg = (
                "Interactive test runs will timeout. Use 'pnpm test:ci' (non-interactive) "
                "or 'pnpm test -- --run' instead.\n"
                "Observed timeouts in recent sessions: pnpm test hangs for 120+ seconds."
            )
            print(msg, file=sys.stderr)
            return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

