import json, sys, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    if tool == "Write":
        content = inp.get("content", "")
    elif tool == "Edit":
        content = inp.get("new_string", "")
    else:
        return 0

    if not content:
        return 0

    # Check for unbounded recursion on tree structures
    for match in re.finditer(r'def\s+(\w+)\s*\([^)]*\):', content):
        func_name = match.group(1)
        # Check if function recursively calls itself on .children/.nodes/etc
        if re.search(rf'{func_name}\s*\([^)]*\.\s*(?:children|nodes|items|subtree)', content):
            # Check for recursion guards
            if not re.search(r'(max_depth|depth_limit|MAX_DEPTH|setrecursionlimit|RecursionError)', content):
                print(
                    f"RECURSION GUARDRAIL: Function '{func_name}' recursively calls itself on tree children "
                    f"without depth limit or recursion guard. This fails on large trees (Python limit ~1000). "
                    f"Use iterative tree traversal (worklist-based) or add explicit depth parameters.",
                    file=sys.stderr
                )
                return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json
import sys
import subprocess
import os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    # Only run on file modification tools
    if tool not in ("Write", "Edit", "MultiEdit"):
        return 0

    # Extract file paths from tool input
    file_paths = []
    if tool in ("Write", "Edit"):
        fp = inp.get("file_path")
        if fp:
            file_paths.append(fp)
    elif tool == "MultiEdit":
        edits = inp.get("edits", [])
        if isinstance(edits, list):
            for edit in edits:
                if isinstance(edit, dict):
                    fp = edit.get("file_path")
                    if fp:
                        file_paths.append(fp)

    # Run ruff format on each modified file
    for fp in file_paths:
        if not os.path.exists(fp):
            continue
        try:
            subprocess.run(
                ["ruff", "format", fp],
                capture_output=True,
                timeout=10
            )
        except Exception:
            pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, re, subprocess, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool not in ("Edit", "Write"):
        return 0

    file_path = inp.get("file_path", "")
    if not (file_path.endswith(".ts") or file_path.endswith(".tsx")):
        return 0

    try:
        with open(file_path, 'r') as f:
            content = f.read()
    except Exception:
        return 0

    # Extract exported identifiers: const, function, class
    pattern = r'export\s+(?:const|function|class)\s+(\w+)'
    matches = re.findall(pattern, content)

    if not matches:
        return 0

    # Find repo root
    repo_root = os.path.dirname(os.path.abspath(file_path))
    for _ in range(10):
        if os.path.exists(os.path.join(repo_root, ".git")):
            break
        parent = os.path.dirname(repo_root)
        if parent == repo_root:
            break
        repo_root = parent

    # Grep for each identifier
    findings = []
    for identifier in set(matches):
        try:
            result = subprocess.run(
                ["grep", "-r", "-n", identifier, "--include=*.ts", "--include=*.tsx", "--include=*.js", "--include=*.jsx", repo_root],
                capture_output=True,
                text=True,
                timeout=10
            )
            if result.stdout:
                refs = result.stdout.strip().split('\n')
                findings.append((identifier, len(refs), refs[:5]))
        except Exception:
            pass

    if findings:
        msg = "EXPORTED IDENTIFIERS — CHECKING REFERENCES:\n"
        for identifier, count, sample_refs in findings:
            msg += f"\n• {identifier} ({count} references):\n"
            for ref in sample_refs:
                msg += f"    {ref}\n"
            if count > 5:
                msg += f"    ... and {count - 5} more\n"
        print(msg, file=sys.stderr)

    return 0

if __name__ == "__main__":
    sys.exit(main())

